  VALUES
  (10, 'display_name', gh_lang_pack(
    $gh$Greenhaven$gh$, $gh$Гринхейвен$gh$, $gh$Грінгейвен$gh$, $gh$Грийнхейвън$gh$, $gh$Гринхејвен$gh$, $gh$Greenhaven$gh$, $gh$Greenhaven$gh$, $gh$Greenhaven$gh$, $gh$Greenhaven$gh$, $gh$Greenhaven$gh$, $gh$Greenhaven$gh$, $gh$גרינהייבן$gh$, $gh$غرينهافن$gh$, $gh$گرین‌هیون$gh$, $gh$گرین ہیون$gh$, $gh$ग्रीनहेवन$gh$, $gh$ग्रीनहेवन$gh$, $gh$ग्रीनहेभन$gh$, $gh$গ্রিনহেভেন$gh$, $gh$กรีนเฮเวน$gh$, $gh$Γκρινχέιβεν$gh$, $gh$Գրինհեյվեն$gh$, $gh$გრინჰეივენი$gh$, $gh$그린헤이븐$gh$, $gh$グリーンヘイヴン$gh$, $gh$绿港$gh$
